import anthropic, json

client = anthropic.Anthropic()

FAIL_POINT_TOOL = {
    "name": "classify_fail_point",
    "description": "Classify a service blueprint fail point by type and assign a mitigation.",
    "input_schema": {
        "type": "object",
        "properties": {
            "stage_id":    {"type": "string"},
            "fail_point":  {"type": "string"},
            "layer":       {"type": "string", "enum": ["front_stage","backstage","support"]},
            "type":        {
                "type": "string",
                "enum": [
                    "model_error",       # Claude produces wrong output
                    "context_loss",      # Multi-turn state not preserved
                    "latency",           # Slow response breaks trust
                    "data_pipeline",     # PDF extraction, PII scrub fails
                    "integration",       # API call, export, downstream system failure
                    "quota_exceeded"     # Rate limit or token quota hit
                ]
            },
            "severity":    {"type": "string", "enum": ["critical","high","medium","low"]},
            "mitigation":  {"type": "string"},
            "eval_test":   {"type": "string"}
        },
        "required": ["stage_id","fail_point","layer","type","severity","mitigation","eval_test"]
    }
}

def analyse_fail_points(blueprint_rows: list[dict]) -> list[dict]:
    """
    For every fail_point in the blueprint, classify it and assign mitigation + eval test.
    """
    all_fails = []
    for row in blueprint_rows:
        for fp in row.get("fail_points", []):
            all_fails.append(f"Stage '{row['stage_label']}' ({row.get('claude_touchpoint','')[:40]}): {fp}")

    if not all_fails:
        return []

    response = client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=2000,
        tools=[FAIL_POINT_TOOL],
        tool_choice={"type": "auto"},
        messages=[{
            "role": "user",
            "content": (
                "Classify each fail point below by layer, type, severity, "
                "and provide a mitigation and a concrete eval test name.\n\n"
                + "\n".join(f"- {f}" for f in all_fails)
            )
        }]
    )
    return [b.input for b in response.content if b.type == "tool_use" and b.name == "classify_fail_point"]

import anthropic, json

client = anthropic.Anthropic()

WAIT_ANALYSIS_TOOL = {
    "name": "analyse_wait_point",
    "description": "Analyse a service blueprint wait point and recommend UX handling.",
    "input_schema": {
        "type": "object",
        "properties": {
            "stage_id":        {"type": "string"},
            "wait_point":      {"type": "string"},
            "expected_latency_ms": {"type": "integer"},
            "is_model_call":   {"type": "boolean"},
            "ux_handling": {
                "type": "string",
                "enum": [
                    "streaming",        # Stream tokens as generated
                    "progress_bar",     # Show determinate progress
                    "spinner",          # Show indeterminate wait
                    "skeleton_ui",      # Show skeleton of expected output shape
                    "background_job"    # Offload; notify when done
                ]
            },
            "fallback_on_timeout": {"type": "string"}
        },
        "required": ["stage_id","wait_point","expected_latency_ms","is_model_call","ux_handling","fallback_on_timeout"]
    }
}

def analyse_wait_points(blueprint_rows: list[dict]) -> list[dict]:
    waits = []
    for row in blueprint_rows:
        for wp in row.get("wait_points", []):
            waits.append(f"Stage '{row['stage_label']}': {wp}")

    if not waits:
        return []

    response = client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=1500,
        tools=[WAIT_ANALYSIS_TOOL],
        tool_choice={"type": "auto"},
        messages=[{
            "role": "user",
            "content": (
                "For each wait point below, estimate latency in ms, "
                "determine if it involves a model call, and recommend UX handling.\n\n"
                + "\n".join(f"- {w}" for w in waits)
            )
        }]
    )
    return [b.input for b in response.content if b.type == "tool_use"]

import anthropic, json
from pathlib import Path

client = anthropic.Anthropic()

EXPORT_TOOL = {
    "name": "format_blueprint_for_export",
    "description": "Format a blueprint stage for Confluence / JIRA export.",
    "input_schema": {
        "type": "object",
        "properties": {
            "stage_id":       {"type": "string"},
            "markdown_table": {"type": "string"},
            "jira_tickets":   {
                "type": "array",
                "items": {
                    "type": "object",
                    "properties": {
                        "summary":    {"type": "string"},
                        "type":       {"type": "string", "enum": ["Bug","Task","Story","Epic"]},
                        "priority":   {"type": "string", "enum": ["Highest","High","Medium","Low"]},
                        "acceptance_criteria": {"type": "string"}
                    },
                    "required": ["summary","type","priority","acceptance_criteria"]
                }
            }
        },
        "required": ["stage_id","markdown_table","jira_tickets"]
    }
}

def export_blueprint_to_jira_tickets(blueprint_rows: list[dict]) -> list[dict]:
    """
    Convert classified fail points and wait points into JIRA-ready ticket specs
    and Confluence-ready markdown tables.
    """
    response = client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=3000,
        tools=[EXPORT_TOOL],
        tool_choice={"type": "auto"},
        messages=[{
            "role": "user",
            "content": (
                "Convert the following service blueprint stages into:\n"
                "1. A Confluence-ready markdown table per stage.\n"
                "2. JIRA tickets for each fail_point and high-latency wait_point.\n\n"
                + json.dumps(blueprint_rows, indent=2)
            )
        }]
    )
    return [b.input for b in response.content if b.type == "tool_use"]
